        $traceText = sprintf(
            "[%s] %s\n  %s: %s\n  at %s:%d\n%s\n\n",
            date('c'),
            $requestLine,
            $e::class,
            $e->getMessage(),
            $e->getFile(),
            $e->getLine(),
            $e->getTraceAsString()
